#!/usr/bin/env python3
"""install_phase2.py — BatKnock Phase 2: photo + heatmap
Run from ~/Desktop/BatKnock:  python3 install_phase2.py
"""
import base64, os, sys
if not os.path.isdir("screens"): sys.exit("Run from BatKnock root")

with open("screens/BatProfileScreen.js", "wb") as f:
    f.write(base64.b64decode(""))
print("✅ screens/BatProfileScreen.js")

with open("screens/HeatmapScreen.js", "wb") as f:
    f.write(base64.b64decode(""))
print("✅ screens/HeatmapScreen.js")

print()
print("Now run:")
print("  npx expo install expo-image-picker")
print("  npx expo start --clear --lan")
print()
print("IMPORTANT: expo-image-picker must be installed before testing photo import.")
